1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	};
8	
9	type Item = { type: string };
10	type Step = { op: "quote"; items: Item[] };
11	type Scenario = { customer: unknown; steps: Step[] };
12	
13	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
14	
15	const quote = (step: Step): { premium: number } => ({
16	  premium: step.items.reduce((sum, item) => sum + itemBasePremium(item), 0) + PROCESSING_FEE,
17	});
18	
19	export const runScenario = (input: unknown): unknown => {
20	  const scenario = input as Scenario;
21	  return { results: scenario.steps.map(quote) };
22	};
